import java.util.Scanner;

public class InvestmentRiskChecker {

    public static void main(String[] args) {

        Scanner input = new Scanner(System.in);

        // Prompt the user to enter their account balance and investment amount
        System.out.print("Enter your current account balance: ");
        double accountBalance = input.nextDouble();
        System.out.print("Enter the investment amount: ");
        double investmentAmount = input.nextDouble();

        // Check if the investment amount is greater than 10% of the account balance
        if (investmentAmount <= accountBalance * 0.1) {
            System.out.println("This investment is safe.");
        } else {
            System.out.println("Warning: This investment is risky and may not be suitable for your financial goals. Please consider your options carefully.");
        }

        input.close();
    }

}

// Note: the multiplication of accountBalance by 0.1 is equivalent to calculating 10% of the account balance.
